#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define pDD pair<LD,LD>
#define fr first
#define se second
#define pb push_back
#define isr insert
#define _i128 __int128
using namespace std;
const int N = 2e5+5;
struct node{int x,delt;LL sum;}a[N];
int n,m,fid[N];LL c[N],Ans;
int read(){
    int su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
bool cmp1(node d1,node d2){return d1.x<d2.x;}
bool cmp2(node d1,node d2){return d1.delt<d2.delt;}
void upd(int x,LL k){while(x<=n)c[x]+=k,x+=x&-x;return;}
LL ask(int x){LL res=0;while(x)res+=c[x],x-=x&-x;return res;}
void CDQsolve(int l,int r){
    if(l==r)return;int mid=(l+r)>>1;
    CDQsolve(l,mid);CDQsolve(mid+1,r);
    int p1=l,p2=mid+1;
    while(p1<=mid){
        while(a[p1].x>a[p2].x&&p2<=r)upd(a[p2].delt,1),p2++;
        a[p1].sum+=ask(m+1)-ask(a[p1].delt),p1++;
    }
    p1=l,p2=mid+1;
    while(p1<=mid){
        while(a[p1].x>a[p2].x&&p2<=r)
            upd(a[p2].delt,-1),p2++;
        p1++;
    }
    p1=mid,p2=r;
    while(p2>mid){
        while(a[p2].x<a[p1].x&&p1>=l)upd(a[p1].delt,1),p1--;
        a[p2].sum+=ask(m+1)-ask(a[p2].delt),p2--;
    }
    p1=mid,p2=r;
    while(p2>mid){
        while(a[p2].x<a[p1].x&&p1>=l)
            upd(a[p1].delt,-1),p1--;
        p2--;
    }
    sort(a+l,a+r+1,cmp1);return;
}
int main(){
    n=read(),m=read();
    for(int i=1;i<=n;i++)
        a[i].x=read(),fid[a[i].x]=i,a[i].delt=m+1;
    for(int i=1;i<=m;i++)a[fid[read()]].delt=i;
    for(int i=1;i<=n;i++)
        Ans+=ask(n)-ask(a[i].x),upd(a[i].x,1);
    for(int i=0;i<=n;i++)c[i]=0;
    CDQsolve(1,n);
    sort(a+1,a+n+1,cmp2);
    for(int i=1;i<=m;i++){cout<<Ans<<"\n";Ans-=a[i].sum;}
    return 0;
}
